package com.example.demo;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api")
public class HelloController {

    private static final Logger logger = LoggerFactory.getLogger(HelloController.class);

    @GetMapping("/hello")
    public ResponseEntity<String> sayHello() {
        logger.info("Received request for /api/hello endpoint.");
        String responseMessage = "Hello from Spring Boot API!";
        logger.info("Successfully processed /api/hello. Responding with: {}", responseMessage);
        return ResponseEntity.ok(responseMessage);
    }

    @GetMapping("/greet/{name}")
    public ResponseEntity<String> greetUser(@PathVariable String name) {
        logger.info("Received request for /api/greet/{} endpoint.", name);

        if (name == null || name.trim().isEmpty()) {
            logger.warn("Received a greet request with an empty or null name. Returning bad request.");
            return ResponseEntity.badRequest().body("Name cannot be empty.");
        }

        String greeting = "Hello, " + name + "!";
        logger.info("Successfully greeted user '{}'. Responding with: {}", name, greeting);
        return ResponseEntity.ok(greeting);
    }
}

